CREATE PROC [dbo].[TR_DINHMUC_GOVAN_Insert] (
   @masp              NVARCHAR (MAX),
   @stt               NVARCHAR (20),
   @chitiet           NVARCHAR (MAX),
   @nguyenlieu        NVARCHAR (MAX),
   @dayy_tc           DECIMAL (18, 2)= 0,
   @rong_tc           DECIMAL (18, 2)= 0,
   @dai_tc            DECIMAL (18, 2)= 0,
   @soluong_tc        INT= 0,
   @m3_tc             DECIMAL (18, 5)= 0,
   @dayy_sc           DECIMAL (18, 2)= 0,
   @rong_sc           DECIMAL (18, 2)= 0,
   @dai_sc            DECIMAL (18, 2)= 0,
   @m3_sc             DECIMAL (18, 5)= 0,
   @dayy_phoi         DECIMAL (18, 2)= 0,
   @ghichu            NVARCHAR (MAX),
   @nguoitao          NVARCHAR (20),
   @nguoisua          NVARCHAR (20),
   @hinhanh           IMAGE= NULL,
   @soluong_mong      INT= 0,
   @kichthuoc_mong    DECIMAL (18, 2)= 0,
   @mong1             DECIMAL (18, 2)= 0,
   @mong2             DECIMAL (18, 2)= 0,
   @veneer_matchinh   NVARCHAR (200)= NULL,
   @veneer_matphu     NVARCHAR (200)= NULL,
   @veneer_canhngan   INT= 0,
   @veneer_canhdai    INT= 0,
   @chatluong         NVARCHAR (100)= NULL,
   @long              NVARCHAR (100)= NULL,
   @bemat             NVARCHAR (MAX)= NULL,
   @chitiet_ghep      NVARCHAR (200)= NULL,
   @phoi_ghep         DECIMAL (18, 2)= 0,
   @t_sort            INT= 0)
AS
BEGIN
   DECLARE @NHOM   NVARCHAR (50);
   SELECT TOP 1 @NHOM = nhom
   FROM tr_nhom_nguyenlieu
   WHERE nguyenlieu = @nguyenlieu

   DECLARE @soluong_sc   FLOAT
   SET @soluong_sc = @soluong_tc

   IF @NHOM = 'VAN'
      BEGIN
         SET @rong_sc = @rong_tc + 0
         SET @dai_sc = @dai_tc + 0
         SET @dayy_sc = @dayy_tc
         SET @m3_sc = (@dayy_sc * @rong_sc * @dai_sc * @soluong_tc) / 1000000000
      END
   ELSE
      BEGIN
		

         IF @nguyenlieu <> ''
            BEGIN
               IF @nguyenlieu <> '0'
                  BEGIN
                     --IF @dayy_tc > 36
                     --   SET @dayy_sc = 36
                     --ELSE
                     --   SET @dayy_sc = @dayy_tc + 1

					 SET @dayy_sc = @dayy_tc + 1

                     IF @rong_tc < 61
                        SET @rong_sc = @rong_tc + 1
                     ELSE
                        SET @rong_sc = 61

                     SET @dai_sc = @dai_tc + 20
                     SET @soluong_sc = 0

                     IF @rong_tc > 60
                        SET @soluong_sc = CEILING(((@rong_tc + 3) * @soluong_tc) / 61)
                     ELSE
                        SET @soluong_sc = @soluong_tc

                     SET @m3_sc = (@dayy_sc * @rong_sc * @dai_sc * @soluong_sc) / 1000000000
                  END
               ELSE
                  BEGIN
                     SET @m3_sc = 0
					 SET @dayy_sc = 0
					 SET @rong_sc = 0
					 SET @dai_tc = 0
					 SET @soluong_sc = 0
                  END
            END
         ELSE
            BEGIN
                SET @m3_sc = 0
				SET @dayy_sc = 0
				SET @rong_sc = 0
				SET @dai_tc = 0
				SET @soluong_sc = 0
            END
      END

   DECLARE @INDEX   INT
   SELECT @INDEX = CHARINDEX (N'cong', @ghichu)

   IF LEN (@long) <= 0 AND @INDEX > 0
      SET @long = N'Lọng'

   DECLARE @IsGhep   BIT
   SET @IsGhep = 0

   IF CHARINDEX ('THONG', @nguyenlieu) > 0 AND @rong_tc > 61
      SET @IsGhep = 1

   IF CHARINDEX ('TRAM', @nguyenlieu) > 0 AND @rong_tc > 61
      SET @IsGhep = 1

   IF CHARINDEX ('DE GAI', @nguyenlieu) > 0 AND @rong_tc > 201
      SET @IsGhep = 1

   INSERT INTO tr_dinhmuc_govan (masp,
                                 mact,
                                 stt,
                                 chitiet,
                                 nguyenlieu,
                                 dayy_tc,
                                 rong_tc,
                                 dai_tc,
                                 soluong_tc,
                                 m3_tc,
                                 dayy_sc,
                                 rong_sc,
                                 dai_sc,
                                 m3_sc,
                                 dayy_phoi,
                                 ghichu,
                                 ngaytao,
                                 nguoitao,
                                 nguoisua,
                                 ngaysua,
                                 hinhanh,
                                 soluong_mong,
                                 kichthuoc_mong,
                                 mong1,
                                 mong2,
                                 veneer_matchinh,
                                 veneer_matphu,
                                 veneer_canhngan,
                                 veneer_canhdai,
                                 chatluong,
                                 long,
                                 bemat,
                                 chitiet_ghep,
                                 phoi_ghep,
                                 soluong_sc,
                                 chitiet_ghep2,
                                 t_sort)
   VALUES (@masp,
           NEXT VALUE FOR dbo.seq_dmgv,
           @stt,
           @chitiet,
           @nguyenlieu,
           @dayy_tc,
           @rong_tc,
           @dai_tc,
           @soluong_tc,
           (@dayy_tc * @rong_tc * @dai_tc * @soluong_tc) / 1000000000,
           @dayy_sc,
           @rong_sc,
           @dai_sc,
           @m3_sc,
           @dayy_phoi,
           @ghichu,
           GETDATE (),
           @nguoitao,
           @nguoisua,
           GETDATE (),
           @hinhanh,
           @soluong_mong,
           @kichthuoc_mong,
           @mong1,
           @mong2,
           @veneer_matchinh,
           @veneer_matphu,
           @veneer_canhngan,
           @veneer_canhdai,
           @chatluong,
           @long,
